import torch
from dataclasses import dataclass, field
from typing import List, Optional

@dataclass
class Block:
    """Represents a physical block of KV cache in GPU VRAM."""
    block_id: int
    block_size: int = 16
    ref_count: int = 1

    def decrement_ref(self) -> int:
        self.ref_count -= 1
        return self.ref_count

    def increment_ref(self) -> int:
        self.ref_count += 1
        return self.ref_count

@dataclass
class BlockTable:
    """Maps a sequence's logical blocks to physical VRAM blocks."""
    logical_to_physical: List[int] = field(default_factory=list)
    block_size: int = 16

class BlockSpaceManager:
    """Manages physical allocation of KV cache blocks via a stack."""

    def __init__(self, num_gpu_blocks: int, block_size: int = 16):
        self.block_size = block_size
        self.total_blocks = num_gpu_blocks
        self.blocks = [Block(i, block_size) for i in range(num_gpu_blocks)]
        self.free_blocks: List[int] = list(range(num_gpu_blocks))

    def can_allocate(self, num_required: int) -> bool:
        """Checks if sufficient physical memory exists."""
        return len(self.free_blocks) >= num_required

    def allocate_block(self) -> int:
        """Pops a free block ID from the memory pool."""
        if not self.free_blocks:
            raise RuntimeError("VRAM Exhausted: Out of KV cache blocks.")
        physical_id = self.free_blocks.pop()
        self.blocks[physical_id].ref_count = 1
        return physical_id

    def free_block(self, block_id: int) -> None:
        """Decrements reference count, returning to pool if zero."""
        block = self.blocks[block_id]
        if block.decrement_ref() == 0:
            self.free_blocks.append(block_id)

    def append_logical_block(self, block_table: BlockTable) -> None:
        """Expands a sequence's capacity by mapping a new physical block."""
        new_physical_id = self.allocate_block()
        block_table.logical_to_physical.append(new_physical_id)
